export interface SpellData {
  name: string;
  level: number;
  school: string;
  castingTime: string;
  range: string;
  components: string;
  duration: string;
  classes: string[];
  description: string;
  upcast?: string;
}

export const SPELL_LIST: SpellData[] = [
  // ─── CANTRIPS (Level 0) ───────────────────────────────────────────────
  { name: 'Acid Splash', level: 0, school: 'Conjuration', castingTime: '1 action', range: '60 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'You hurl a bubble of acid. Choose one creature within range, or choose two creatures within range that are within 5 feet of each other. A target must succeed on a DEX saving throw or take 1d6 acid damage.' },
  { name: 'Blade Ward', level: 0, school: 'Abjuration', castingTime: '1 action', range: 'Self', components: 'V, S', duration: '1 round', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'You extend your hand and trace a sigil of warding in the air. Until the end of your next turn, you have resistance against bludgeoning, piercing, and slashing damage dealt by weapon attacks.' },
  { name: 'Chill Touch', level: 0, school: 'Necromancy', castingTime: '1 action', range: '120 feet', components: 'V, S', duration: '1 round', classes: ['Sorcerer', 'Warlock', 'Wizard'], description: 'You create a ghostly, skeletal hand in the space of a creature within range. Make a ranged spell attack. On a hit, the target takes 1d8 necrotic damage, and it can\'t regain hit points until the start of your next turn.' },
  { name: 'Dancing Lights', level: 0, school: 'Evocation', castingTime: '1 action', range: '120 feet', components: 'V, S, M (a bit of phosphorus or wychwood, or a glowworm)', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Sorcerer', 'Wizard'], description: 'You create up to four torch-sized lights within range, making them appear as torches, lanterns, or glowing orbs that hover in the air. You can move them up to 60 feet as a bonus action.' },
  { name: 'Druidcraft', level: 0, school: 'Transmutation', castingTime: '1 action', range: '30 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Druid'], description: 'Whispering to the spirits of nature, you create one of the following effects: predict weather, make a flower bloom, create a tiny sensory effect, or light or snuff out a candle, torch, or small campfire.' },
  { name: 'Eldritch Blast', level: 0, school: 'Evocation', castingTime: '1 action', range: '120 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Warlock'], description: 'A beam of crackling energy streaks toward a creature within range. Make a ranged spell attack. On a hit, the target takes 1d10 force damage. The spell creates more than one beam when you reach higher levels: two beams at 5th, three at 11th, four at 17th.' },
  { name: 'Fire Bolt', level: 0, school: 'Evocation', castingTime: '1 action', range: '120 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'You hurl a mote of fire at a creature or object within range. Make a ranged spell attack. On a hit, the target takes 1d10 fire damage. A flammable object hit by this spell ignites if it isn\'t being worn or carried.' },
  { name: 'Friends', level: 0, school: 'Enchantment', castingTime: '1 action', range: 'Self', components: 'S, M (a small amount of makeup)', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'For the duration, you have advantage on all Charisma checks directed at one creature of your choice that isn\'t hostile toward you. When the spell ends, the creature realizes it was charmed.' },
  { name: 'Guidance', level: 0, school: 'Divination', castingTime: '1 action', range: 'Touch', components: 'V, S', duration: 'Concentration, up to 1 minute', classes: ['Cleric', 'Druid'], description: 'You touch one willing creature. Once before the spell ends, the target can roll a d4 and add the number rolled to one ability check of its choice. It can roll the die before or after making the ability check.' },
  { name: 'Light', level: 0, school: 'Evocation', castingTime: '1 action', range: 'Touch', components: 'V, M (a firefly or phosphorescent moss)', duration: '1 hour', classes: ['Bard', 'Cleric', 'Sorcerer', 'Wizard'], description: 'You touch one object that is no larger than 10 feet in any dimension. Until the spell ends, the object sheds bright light in a 20-foot radius and dim light for an additional 20 feet.' },
  { name: 'Mage Hand', level: 0, school: 'Conjuration', castingTime: '1 action', range: '30 feet', components: 'V, S', duration: '1 minute', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'A spectral, floating hand appears at a point you choose within range. The hand lasts for the duration or until you dismiss it. The hand vanishes if it is ever more than 30 feet away from you or if you cast this spell again.' },
  { name: 'Mending', level: 0, school: 'Transmutation', castingTime: '1 minute', range: 'Touch', components: 'V, S, M', duration: 'Instantaneous', classes: ['Bard', 'Cleric', 'Druid', 'Sorcerer', 'Wizard'], description: 'This spell repairs a single break or tear in an object you touch, such as broken chain link, two halves of a broken key, a torn cloak, or a leaking wineskin. As long as the break or tear is no larger than 1 foot in any dimension, you mend it, leaving no trace of the former damage.' },
  { name: 'Message', level: 0, school: 'Transmutation', castingTime: '1 action', range: '120 feet', components: 'V, S, M (a short piece of copper wire)', duration: '1 round', classes: ['Bard', 'Sorcerer', 'Wizard'], description: 'You point your finger toward a creature within range and whisper a message. The target (and only the target) hears the message and can reply in a whisper that only you can hear.' },
  { name: 'Minor Illusion', level: 0, school: 'Illusion', castingTime: '1 action', range: '30 feet', components: 'S, M (a bit of fleece)', duration: '1 minute', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'You create a sound or an image of an object within range that lasts for the duration. The illusion also ends if you dismiss it as an action or cast this spell again.' },
  { name: 'Poison Spray', level: 0, school: 'Conjuration', castingTime: '1 action', range: '10 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Druid', 'Sorcerer', 'Warlock', 'Wizard'], description: 'You extend your hand toward a creature you can see within range and project a puff of noxious gas. The creature must succeed on a CON saving throw or take 1d12 poison damage.' },
  { name: 'Prestidigitation', level: 0, school: 'Transmutation', castingTime: '1 action', range: '10 feet', components: 'V, S', duration: 'Up to 1 hour', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'This spell is a minor magical trick that novice spellcasters use for practice. You create one of the following magical effects within range: a harmless sensory effect, light or snuff a candle, clean or soil an object, chill/warm/flavor a material, create a color or mark, create a small trinket or illusory image.' },
  { name: 'Ray of Frost', level: 0, school: 'Evocation', castingTime: '1 action', range: '60 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'A frigid beam of blue-white light streaks toward a creature within range. Make a ranged spell attack. On a hit, it takes 1d8 cold damage, and its speed is reduced by 10 feet until the start of your next turn.' },
  { name: 'Sacred Flame', level: 0, school: 'Evocation', castingTime: '1 action', range: '60 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Cleric'], description: 'Flame-like radiance descends on a creature that you can see within range. The target must succeed on a DEX saving throw or take 1d8 radiant damage. The target gains no benefit from cover for this saving throw.' },
  { name: 'Shillelagh', level: 0, school: 'Transmutation', castingTime: '1 bonus action', range: 'Touch', components: 'V, S, M (mistletoe, a shamrock leaf, and a club or quarterstaff)', duration: '1 minute', classes: ['Druid'], description: 'The wood of a club or quarterstaff you are holding is imbued with nature\'s power. For the duration, you can use your spellcasting ability instead of STR for attack and damage rolls, and the weapon\'s damage die becomes a d8. The weapon also becomes magical.' },
  { name: 'Shocking Grasp', level: 0, school: 'Evocation', castingTime: '1 action', range: 'Touch', components: 'V, S', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'Lightning springs from your hand to deliver a shock to a creature you try to touch. Make a melee spell attack. You have advantage if the target is wearing armor made of metal. On a hit, the target takes 1d8 lightning damage and can\'t take reactions until the start of its next turn.' },
  { name: 'Spare the Dying', level: 0, school: 'Necromancy', castingTime: '1 action', range: 'Touch', components: 'V, S', duration: 'Instantaneous', classes: ['Cleric'], description: 'You touch a living creature that has 0 hit points. The creature becomes stable. This spell has no effect on undead or constructs.' },
  { name: 'Thaumaturgy', level: 0, school: 'Transmutation', castingTime: '1 action', range: '30 feet', components: 'V', duration: 'Up to 1 minute', classes: ['Cleric'], description: 'You manifest a minor wonder, a sign of supernatural power. You create one of the following magical effects: your voice booms; flames flicker or change color; harmless tremors; an instantaneous sound; a door or window flies open/shut; or your eyes change color.' },
  { name: 'Toll the Dead', level: 0, school: 'Necromancy', castingTime: '1 action', range: '60 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Cleric', 'Warlock', 'Wizard'], description: 'You point at one creature you can see within range, and the sound of a dolorous bell fills the air around it for a moment. The target must succeed on a WIS saving throw or take 1d8 necrotic damage. If the target is missing any of its hit points, it instead takes 1d12 necrotic damage.' },
  { name: 'True Strike', level: 0, school: 'Divination', castingTime: '1 action', range: '30 feet', components: 'S', duration: 'Concentration, up to 1 round', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'You extend your hand and point a finger at a target in range. Your magic grants you a brief insight into the target\'s defenses. On your next turn, you gain advantage on your first attack roll against the target, provided that this spell hasn\'t ended.' },
  { name: 'Vicious Mockery', level: 0, school: 'Enchantment', castingTime: '1 action', range: '60 feet', components: 'V', duration: 'Instantaneous', classes: ['Bard'], description: 'You unleash a string of insults laced with subtle enchantments at a creature you can see within range. If the target can hear you (it need not understand you), it must succeed on a WIS saving throw or take 1d4 psychic damage and have disadvantage on the next attack roll it makes before the end of its next turn.' },
  { name: 'Word of Radiance', level: 0, school: 'Evocation', castingTime: '1 action', range: '5 feet', components: 'V, M (a holy symbol)', duration: 'Instantaneous', classes: ['Cleric'], description: 'You utter a divine word, and burning radiance erupts from you. Each creature of your choice that you can see within range must succeed on a CON saving throw or take 1d6 radiant damage.' },

  // ─── LEVEL 1 ──────────────────────────────────────────────────────────
  { name: 'Arms of Hadar', level: 1, school: 'Conjuration', castingTime: '1 action', range: 'Self (10-foot radius)', components: 'V, S', duration: 'Instantaneous', classes: ['Warlock'], description: 'You invoke the power of Hadar, the Dark Hunger. Tendrils of dark energy erupt from you and batter all creatures within 10 feet. Each creature in that area must make a STR saving throw. On a failed save, a target takes 2d6 necrotic damage and can\'t take reactions until its next turn. On a successful save, the creature takes half damage, but suffers no other effect.', upcast: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.' },
  { name: 'Bless', level: 1, school: 'Enchantment', castingTime: '1 action', range: '30 feet', components: 'V, S, M (a sprinkling of holy water)', duration: 'Concentration, up to 1 minute', classes: ['Cleric', 'Paladin'], description: 'You bless up to three creatures of your choice within range. Whenever a target makes an attack roll or a saving throw before the spell ends, the target can roll a d4 and add the number rolled to the attack roll or saving throw.', upcast: 'When you cast this spell using a slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.' },
  { name: 'Burning Hands', level: 1, school: 'Evocation', castingTime: '1 action', range: 'Self (15-foot cone)', components: 'V, S', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'As you hold your hands with thumbs touching and fingers spread, a thin sheet of flames shoots forth. Each creature in a 15-foot cone must make a DEX saving throw. On a failed save, a creature takes 3d6 fire damage, or half as much on a successful save.', upcast: 'When cast using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.' },
  { name: 'Charm Person', level: 1, school: 'Enchantment', castingTime: '1 action', range: '30 feet', components: 'V, S', duration: '1 hour', classes: ['Bard', 'Druid', 'Sorcerer', 'Warlock', 'Wizard'], description: 'You attempt to charm a humanoid you can see within range. It must make a WIS saving throw, and does so with advantage if you or your companions are fighting it. If it fails, it is charmed by you until the spell ends or until you or your companions do anything harmful to it. The charmed creature regards you as a friendly acquaintance.' },
  { name: 'Command', level: 1, school: 'Enchantment', castingTime: '1 action', range: '60 feet', components: 'V', duration: '1 round', classes: ['Cleric', 'Paladin'], description: 'You speak a one-word command to a creature you can see within range. The target must succeed on a WIS saving throw or follow the command on its next turn. The spell has no effect if the target is undead, if it doesn\'t understand your language, or if your command is directly harmful to it. Common commands: Approach, Drop, Flee, Grovel, Halt.' },
  { name: 'Comprehend Languages', level: 1, school: 'Divination', castingTime: '1 action (ritual)', range: 'Self', components: 'V, S, M (a pinch of soot and salt)', duration: '1 hour', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'For the duration, you understand the literal meaning of any spoken language that you hear. You also understand any written language that you see, but you must be touching the surface on which the words are written.' },
  { name: 'Cure Wounds', level: 1, school: 'Evocation', castingTime: '1 action', range: 'Touch', components: 'V, S', duration: 'Instantaneous', classes: ['Bard', 'Cleric', 'Druid', 'Paladin', 'Ranger'], description: 'A creature you touch regains a number of hit points equal to 1d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', upcast: 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d8 for each slot level above 1st.' },
  { name: 'Detect Magic', level: 1, school: 'Divination', castingTime: '1 action (ritual)', range: 'Self', components: 'V, S', duration: 'Concentration, up to 10 minutes', classes: ['Bard', 'Cleric', 'Druid', 'Paladin', 'Ranger', 'Sorcerer', 'Wizard'], description: 'For the duration, you sense the presence of magic within 30 feet of you. If you sense magic in this way, you can use your action to see a faint aura around any visible creature or object in the area that bears magic, and you learn its school of magic, if any.' },
  { name: 'Disguise Self', level: 1, school: 'Illusion', castingTime: '1 action', range: 'Self', components: 'V, S', duration: '1 hour', classes: ['Bard', 'Sorcerer', 'Wizard'], description: 'You make yourself — including your clothing, armor, weapons, and other belongings on your person — look different until the spell ends or until you use your action to dismiss it. You can seem up to 1 foot shorter or taller and appear thin, fat, or in between.' },
  { name: 'Dissonant Whispers', level: 1, school: 'Enchantment', castingTime: '1 action', range: '60 feet', components: 'V', duration: 'Instantaneous', classes: ['Bard'], description: 'You whisper a discordant melody that only one creature of your choice within range can hear. The target must make a WIS saving throw. On a failed save, it takes 3d6 psychic damage and must immediately use its reaction to move as far as its speed allows away from you. On a successful save, the creature takes half as much damage and doesn\'t need to move away.' },
  { name: 'Divine Favor', level: 1, school: 'Evocation', castingTime: '1 bonus action', range: 'Self', components: 'V, S', duration: 'Concentration, up to 1 minute', classes: ['Paladin'], description: 'Your prayer empowers you with divine radiance. Until the spell ends, your weapon attacks deal an extra 1d4 radiant damage on a hit.' },
  { name: 'Entangle', level: 1, school: 'Conjuration', castingTime: '1 action', range: '90 feet', components: 'V, S', duration: 'Concentration, up to 1 minute', classes: ['Druid'], description: 'Grasping weeds and vines sprout from the ground in a 20-foot square within range. Creatures in the area when cast must succeed on a STR saving throw or be restrained until the spell ends. A creature restrained can use its action to make a STR check against your spell save DC.' },
  { name: 'Expeditious Retreat', level: 1, school: 'Transmutation', castingTime: '1 bonus action', range: 'Self', components: 'V, S', duration: 'Concentration, up to 10 minutes', classes: ['Sorcerer', 'Warlock', 'Wizard'], description: 'This spell allows you to move at an incredible pace. When you cast this spell, and then as a bonus action on each of your turns until the spell ends, you can take the Dash action.' },
  { name: 'Faerie Fire', level: 1, school: 'Evocation', castingTime: '1 action', range: '60 feet', components: 'V', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Druid'], description: 'Each object in a 20-foot cube within range is outlined in blue, green, or violet light. Any creature in the area when the spell is cast is also outlined in light if it fails a DEX saving throw. For the duration, objects and affected creatures shed dim light in a 10-foot radius. Attack rolls against an affected creature or object have advantage if the attacker can see it, and the affected creature or object can\'t benefit from being invisible.' },
  { name: 'Fog Cloud', level: 1, school: 'Conjuration', castingTime: '1 action', range: '120 feet', components: 'V, S', duration: 'Concentration, up to 1 hour', classes: ['Druid', 'Ranger', 'Sorcerer', 'Wizard'], description: 'You create a 20-foot-radius sphere of fog centered on a point within range. The sphere spreads around corners, and its area is heavily obscured. It lasts for the duration or until a wind of moderate or greater speed disperses it.' },
  { name: 'Goodberry', level: 1, school: 'Transmutation', castingTime: '1 action', range: 'Touch', components: 'V, S, M (a sprig of mistletoe)', duration: 'Instantaneous', classes: ['Druid', 'Ranger'], description: 'Up to ten berries appear in your hand and are infused with magic for the duration. A creature can use its action to eat one berry. Eating a berry restores 1 hit point, and the berry provides enough nourishment to sustain a creature for one day.' },
  { name: 'Guiding Bolt', level: 1, school: 'Evocation', castingTime: '1 action', range: '120 feet', components: 'V, S', duration: '1 round', classes: ['Cleric'], description: 'A flash of light streaks toward a creature of your choice within range. Make a ranged spell attack. On a hit, the target takes 4d6 radiant damage, and the next attack roll made against this target before the end of your next turn has advantage.', upcast: 'When cast using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.' },
  { name: 'Healing Word', level: 1, school: 'Evocation', castingTime: '1 bonus action', range: '60 feet', components: 'V', duration: 'Instantaneous', classes: ['Bard', 'Cleric', 'Druid'], description: 'A creature of your choice that you can see within range regains hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', upcast: 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d4 for each slot level above 1st.' },
  { name: 'Hellish Rebuke', level: 1, school: 'Evocation', castingTime: '1 reaction', range: '60 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Warlock'], description: 'You point your finger, and the creature that damaged you is momentarily surrounded by hellish flames. The creature must make a DEX saving throw. It takes 2d10 fire damage on a failed save, or half as much on a successful one.', upcast: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.' },
  { name: 'Heroism', level: 1, school: 'Enchantment', castingTime: '1 action', range: 'Touch', components: 'V, S', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Paladin'], description: 'A willing creature you touch is imbued with bravery. Until the spell ends, the creature is immune to being frightened and gains temporary hit points equal to your spellcasting ability modifier at the start of each of its turns.', upcast: 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.' },
  { name: 'Hex', level: 1, school: 'Enchantment', castingTime: '1 bonus action', range: '90 feet', components: 'V, S, M (the petrified eye of a newt)', duration: 'Concentration, up to 1 hour', classes: ['Warlock'], description: 'You place a curse on a creature that you can see within range. Until the spell ends, you deal an extra 1d6 necrotic damage to the target whenever you hit it with an attack. Also, choose one ability when you cast the spell. The target has disadvantage on ability checks made with the chosen ability.', upcast: 'When you cast this spell using a spell slot of 3rd or 4th level, you can maintain your concentration on the spell for up to 8 hours. When you use a spell slot of 5th level or higher, you can maintain concentration for up to 24 hours.' },
  { name: 'Hunter\'s Mark', level: 1, school: 'Divination', castingTime: '1 bonus action', range: '90 feet', components: 'V', duration: 'Concentration, up to 1 hour', classes: ['Ranger'], description: 'You choose a creature you can see within range and mystically mark it as your quarry. Until the spell ends, you deal an extra 1d6 damage to the target whenever you hit it with a weapon attack, and you have advantage on any WIS (Perception) or WIS (Survival) check you make to find it.' },
  { name: 'Identify', level: 1, school: 'Divination', castingTime: '1 minute (ritual)', range: 'Touch', components: 'V, S, M (a pearl worth at least 100 gp and an owl feather)', duration: 'Instantaneous', classes: ['Bard', 'Wizard'], description: 'You choose one object that you must touch throughout the casting of the spell. If it is a magic item or some other magic-imbued object, you learn its properties and how to use them, whether it requires attunement to use, and how many charges it has, if any.' },
  { name: 'Inflict Wounds', level: 1, school: 'Necromancy', castingTime: '1 action', range: 'Touch', components: 'V, S', duration: 'Instantaneous', classes: ['Cleric'], description: 'Make a melee spell attack against a creature you can reach. On a hit, the target takes 3d10 necrotic damage.', upcast: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.' },
  { name: 'Longstrider', level: 1, school: 'Transmutation', castingTime: '1 action', range: 'Touch', components: 'V, S, M (a pinch of dirt)', duration: '1 hour', classes: ['Bard', 'Druid', 'Ranger', 'Wizard'], description: 'You touch a creature. The target\'s speed increases by 10 feet until the spell ends.', upcast: 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.' },
  { name: 'Mage Armor', level: 1, school: 'Abjuration', castingTime: '1 action', range: 'Touch', components: 'V, S, M (a piece of cured leather)', duration: '8 hours', classes: ['Sorcerer', 'Wizard'], description: 'You touch a willing creature who isn\'t wearing armor, and a protective magical force surrounds it until the spell ends. The target\'s base AC becomes 13 + its Dexterity modifier. The spell ends if the target dons armor or if you dismiss the spell as an action.' },
  { name: 'Magic Missile', level: 1, school: 'Evocation', castingTime: '1 action', range: '120 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'You create three glowing darts of magical force. Each dart hits a creature of your choice that you can see within range. A dart deals 1d4+1 force damage to its target. The darts all strike simultaneously, and you can direct them to hit one creature or several.', upcast: 'When you cast this spell using a spell slot of 2nd level or higher, the spell creates one more dart for each slot level above 1st.' },
  { name: 'Protection from Evil and Good', level: 1, school: 'Abjuration', castingTime: '1 action', range: 'Touch', components: 'V, S, M (holy water or powdered silver and iron)', duration: 'Concentration, up to 10 minutes', classes: ['Cleric', 'Paladin', 'Warlock', 'Wizard'], description: 'Until the spell ends, one willing creature you touch is protected against aberrations, celestials, elementals, fey, fiends, and undead. The protection grants several benefits: the creature can\'t be charmed, frightened, or possessed by them; they have disadvantage on attack rolls against it.' },
  { name: 'Shield', level: 1, school: 'Abjuration', castingTime: '1 reaction', range: 'Self', components: 'V, S', duration: '1 round', classes: ['Sorcerer', 'Wizard'], description: 'An invisible barrier of magical force appears and protects you. Until the start of your next turn, you have a +5 bonus to AC, including against the triggering attack, and you take no damage from magic missile.' },
  { name: 'Shield of Faith', level: 1, school: 'Abjuration', castingTime: '1 bonus action', range: '60 feet', components: 'V, S, M (a small parchment with a bit of holy text)', duration: 'Concentration, up to 10 minutes', classes: ['Cleric', 'Paladin'], description: 'A shimmering field appears and surrounds a creature of your choice within range, granting it a +2 bonus to AC for the duration.' },
  { name: 'Sleep', level: 1, school: 'Enchantment', castingTime: '1 action', range: '90 feet', components: 'V, S, M (fine sand, rose petals, or a cricket)', duration: '1 minute', classes: ['Bard', 'Sorcerer', 'Wizard'], description: 'This spell sends creatures into a magical slumber. Roll 5d8; the total is how many hit points of creatures this spell can affect. Creatures within 20 feet of a point you choose are affected in ascending order of their current hit points (ignoring unconscious creatures).', upcast: 'When you cast this spell using a spell slot of 2nd level or higher, roll an additional 2d8 for each slot level above 1st.' },
  { name: 'Speak with Animals', level: 1, school: 'Divination', castingTime: '1 action (ritual)', range: 'Self', components: 'V, S', duration: '10 minutes', classes: ['Bard', 'Druid', 'Ranger'], description: 'You gain the ability to comprehend and verbally communicate with beasts for the duration. The knowledge and awareness of many beasts is limited by their intelligence, but at minimum, beasts can give you information about nearby locations and monsters, including whatever they can perceive or have perceived within the past day.' },
  { name: 'Thunderwave', level: 1, school: 'Evocation', castingTime: '1 action', range: 'Self (15-foot cube)', components: 'V, S', duration: 'Instantaneous', classes: ['Bard', 'Druid', 'Sorcerer', 'Wizard'], description: 'A wave of thunderous force sweeps out from you. Each creature in a 15-foot cube originating from you must make a CON saving throw. On a failed save, a creature takes 2d8 thunder damage and is pushed 10 feet away from you. On a successful save, the creature takes half damage and isn\'t pushed.', upcast: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d8 for each slot level above 1st.' },
  { name: 'Witch Bolt', level: 1, school: 'Evocation', castingTime: '1 action', range: '30 feet', components: 'V, S, M (a twig from a tree that has been struck by lightning)', duration: 'Concentration, up to 1 minute', classes: ['Sorcerer', 'Warlock', 'Wizard'], description: 'A beam of crackling, blue energy lances out toward a creature within range, forming a sustained arc of lightning between you and the target. Make a ranged spell attack. On a hit, the target takes 1d12 lightning damage, and on each of your turns for the duration, you can use your action to deal 1d12 lightning damage to the target automatically.', upcast: 'When you cast this spell using a spell slot of 2nd level or higher, the initial damage increases by 1d12 for each slot level above 1st.' },
  { name: 'Wrathful Smite', level: 1, school: 'Evocation', castingTime: '1 bonus action', range: 'Self', components: 'V', duration: 'Concentration, up to 1 minute', classes: ['Paladin'], description: 'The next time you hit with a melee weapon attack during this spell\'s duration, your attack deals an extra 1d6 psychic damage. Additionally, if the target is a creature, it must make a WIS saving throw or be frightened of you until the spell ends.' },

  // ─── LEVEL 2 ──────────────────────────────────────────────────────────
  { name: 'Aid', level: 2, school: 'Abjuration', castingTime: '1 action', range: '30 feet', components: 'V, S, M (a tiny strip of white cloth)', duration: '8 hours', classes: ['Cleric', 'Paladin'], description: 'Your spell bolsters your allies with toughness and resolve. Choose up to three creatures within range. Each target\'s hit point maximum and current hit points increase by 5 for the duration.', upcast: 'When you cast this spell using a spell slot of 3rd level or higher, a target\'s hit points increase by an additional 5 for each slot level above 2nd.' },
  { name: 'Arcane Lock', level: 2, school: 'Abjuration', castingTime: '1 action', range: 'Touch', components: 'V, S, M (gold dust worth at least 25 gp)', duration: 'Until dispelled', classes: ['Wizard'], description: 'You touch a closed door, window, gate, chest, or other entryway, and it becomes locked for the duration. You and the creatures you designate when you cast this spell can open the object normally. You can also set a password that, when spoken within 5 feet, suppresses this spell for 1 minute.' },
  { name: 'Blindness/Deafness', level: 2, school: 'Necromancy', castingTime: '1 action', range: '30 feet', components: 'V', duration: '1 minute', classes: ['Bard', 'Cleric', 'Sorcerer', 'Wizard'], description: 'You can blind or deafen a foe. Choose one creature that you can see within range to make a CON saving throw. If it fails, the target is either blinded or deafened (your choice) for the duration.', upcast: 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.' },
  { name: 'Blur', level: 2, school: 'Illusion', castingTime: '1 action', range: 'Self', components: 'V', duration: 'Concentration, up to 1 minute', classes: ['Sorcerer', 'Wizard'], description: 'Your body becomes blurred, shifting and wavering to all who can see you. For the duration, any creature has disadvantage on attack rolls against you. An attacker is immune to this effect if it doesn\'t rely on sight, as with blindsight, or can see through illusions, as with truesight.' },
  { name: 'Branding Smite', level: 2, school: 'Evocation', castingTime: '1 bonus action', range: 'Self', components: 'V', duration: 'Concentration, up to 1 minute', classes: ['Paladin'], description: 'The next time you hit a creature with a weapon attack before this spell ends, the weapon gleams with astral radiance as you strike. The attack deals an extra 2d6 radiant damage to the target. The target becomes visible if it\'s invisible, and it sheds dim light in a 5-foot radius and can\'t become invisible until the spell ends.' },
  { name: 'Calm Emotions', level: 2, school: 'Enchantment', castingTime: '1 action', range: '60 feet', components: 'V, S', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Cleric'], description: 'You attempt to suppress strong emotions in a group of people. Each humanoid in a 20-foot-radius sphere centered on a point you choose within range must make a CHA saving throw; a creature can choose to fail this saving throw if it wishes. If a creature fails its saving throw, choose one of two effects: suppress any effect causing the target to be charmed or frightened; or make the target indifferent about creatures of your choice that it is hostile toward.' },
  { name: 'Darkness', level: 2, school: 'Evocation', castingTime: '1 action', range: '60 feet', components: 'V, M (bat fur and a drop of pitch or piece of coal)', duration: 'Concentration, up to 10 minutes', classes: ['Sorcerer', 'Warlock', 'Wizard'], description: 'Magical darkness spreads from a point you choose within range to fill a 15-foot-radius sphere for the duration. The darkness spreads around corners. A creature with darkvision can\'t see through this darkness, and nonmagical light can\'t illuminate it.' },
  { name: 'Darkvision', level: 2, school: 'Transmutation', castingTime: '1 action', range: 'Touch', components: 'V, S, M (either a pinch of dried carrot or an agate)', duration: '8 hours', classes: ['Druid', 'Ranger', 'Sorcerer', 'Wizard'], description: 'You touch a willing creature to grant it the ability to see in the dark. For the duration, that creature has darkvision out to a range of 60 feet.' },
  { name: 'Enhance Ability', level: 2, school: 'Transmutation', castingTime: '1 action', range: 'Touch', components: 'V, S, M (fur or a feather from a beast)', duration: 'Concentration, up to 1 hour', classes: ['Bard', 'Cleric', 'Druid', 'Sorcerer', 'Wizard'], description: 'You touch a creature and bestow upon it a magical enhancement. Choose one of the following effects: Bull\'s Strength (advantage on STR checks, carry capacity doubles), Cat\'s Grace (advantage on DEX checks, no damage from falls under 20 feet), Bear\'s Endurance (advantage on CON checks, +2d6 temp HP), Fox\'s Cunning (advantage on INT checks), Owl\'s Wisdom (advantage on WIS checks), Eagle\'s Splendor (advantage on CHA checks).' },
  { name: 'Enthrall', level: 2, school: 'Enchantment', castingTime: '1 action', range: '60 feet', components: 'V, S', duration: '1 minute', classes: ['Bard', 'Warlock'], description: 'You weave a distracting string of words, causing creatures of your choice that you can see within range and that can hear you to make a WIS saving throw. Any creature that fails its saving throw has disadvantage on WIS (Perception) checks made to perceive any creature other than you until the spell ends.' },
  { name: 'Find Traps', level: 2, school: 'Divination', castingTime: '1 action', range: '120 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Cleric', 'Druid', 'Ranger'], description: 'You sense the presence of any trap within range that is within line of sight. A trap, for the purpose of this spell, includes anything that would inflict a sudden or unexpected effect you consider harmful or undesirable, which was specifically intended as such by its creator.' },
  { name: 'Flaming Sphere', level: 2, school: 'Conjuration', castingTime: '1 action', range: '60 feet', components: 'V, S, M (a bit of tallow, a pinch of brimstone, and a dusting of powdered iron)', duration: 'Concentration, up to 1 minute', classes: ['Druid', 'Wizard'], description: 'A 5-foot-diameter sphere of fire appears in an unoccupied space of your choice within range and lasts for the duration. Any creature that ends its turn within 5 feet of the sphere must make a DEX saving throw. The creature takes 2d6 fire damage on a failed save, or half as much on a successful one.' },
  { name: 'Gentle Repose', level: 2, school: 'Necromancy', castingTime: '1 action (ritual)', range: 'Touch', components: 'V, S, M (a pinch of salt and one copper piece placed on each of the corpse\'s eyes)', duration: '10 days', classes: ['Cleric', 'Wizard'], description: 'You touch a corpse or other remains. For the duration, the target is protected from decay and can\'t become undead. The spell also extends the time limit on raising the target from the dead, since days spent under the influence of this spell don\'t count against the limit of spells such as raise dead.' },
  { name: 'Hold Person', level: 2, school: 'Enchantment', castingTime: '1 action', range: '60 feet', components: 'V, S, M (a small, straight piece of iron)', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Cleric', 'Druid', 'Sorcerer', 'Warlock', 'Wizard'], description: 'Choose a humanoid that you can see within range. The target must succeed on a WIS saving throw or be paralyzed for the duration. At the end of each of its turns, the target can make another WIS saving throw. On a success, the spell ends on the target.', upcast: 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional humanoid for each slot level above 2nd.' },
  { name: 'Invisibility', level: 2, school: 'Illusion', castingTime: '1 action', range: 'Touch', components: 'V, S, M (an eyelash encased in gum arabic)', duration: 'Concentration, up to 1 hour', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'A creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target\'s person. The spell ends for a target that attacks or casts a spell.', upcast: 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.' },
  { name: 'Magic Weapon', level: 2, school: 'Transmutation', castingTime: '1 bonus action', range: 'Touch', components: 'V, S', duration: 'Concentration, up to 1 hour', classes: ['Paladin', 'Wizard'], description: 'You touch a nonmagical weapon. Until the spell ends, that weapon becomes a magic weapon with a +1 bonus to attack rolls and damage rolls.', upcast: 'When you cast this spell using a spell slot of 4th level or higher, the bonus increases to +2. When you use a spell slot of 6th level or higher, the bonus increases to +3.' },
  { name: 'Mirror Image', level: 2, school: 'Illusion', castingTime: '1 action', range: 'Self', components: 'V, S', duration: '1 minute', classes: ['Sorcerer', 'Warlock', 'Wizard'], description: 'Three illusory duplicates of yourself appear in your space. Until the spell ends, the duplicates move with you and mimic your actions, shifting position so it\'s impossible to track which image is real. Each time a creature targets you with an attack, roll a d20 to determine whether the attack targets you or one of your duplicates.' },
  { name: 'Misty Step', level: 2, school: 'Conjuration', castingTime: '1 bonus action', range: 'Self', components: 'V', duration: 'Instantaneous', classes: ['Sorcerer', 'Warlock', 'Wizard'], description: 'Briefly surrounded by silvery mist, you teleport up to 30 feet to an unoccupied space that you can see.' },
  { name: 'Moonbeam', level: 2, school: 'Evocation', castingTime: '1 action', range: '120 feet', components: 'V, S, M (several seeds of any moonseed plant and a piece of opalescent feldspar)', duration: 'Concentration, up to 1 minute', classes: ['Druid'], description: 'A silvery beam of pale light shines down in a 5-foot-radius, 40-foot-high cylinder centered on a point within range. Until the spell ends, dim light fills the cylinder. When a creature enters the spell\'s area for the first time on a turn or starts its turn there, it is engulfed in ghostly flames that cause searing pain, and it must make a CON saving throw. It takes 2d10 radiant damage on a failed save.' },
  { name: 'Pass without Trace', level: 2, school: 'Abjuration', castingTime: '1 action', range: 'Self', components: 'V, S, M (ashes from a burned leaf of mistletoe and a sprig of spruce)', duration: 'Concentration, up to 1 hour', classes: ['Druid', 'Ranger'], description: 'A veil of shadows and silence radiates from you, masking you and your companions from detection. For the duration, each creature you choose within 30 feet of you (including you) has a +10 bonus to Dexterity (Stealth) checks and can\'t be tracked except by magical means.' },
  { name: 'Prayer of Healing', level: 2, school: 'Evocation', castingTime: '10 minutes', range: '30 feet', components: 'V', duration: 'Instantaneous', classes: ['Cleric'], description: 'Up to six creatures of your choice that you can see within range each regain hit points equal to 2d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', upcast: 'When you cast this spell using a spell slot of 3rd level or higher, the healing increases by 1d8 for each slot level above 2nd.' },
  { name: 'Shatter', level: 2, school: 'Evocation', castingTime: '1 action', range: '60 feet', components: 'V, S, M (a chip of mica)', duration: 'Instantaneous', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'A sudden loud ringing noise, painfully intense, erupts from a point of your choice within range. Each creature in a 10-foot-radius sphere centered on that point must make a CON saving throw. A creature takes 3d8 thunder damage on a failed save, or half as much on a successful one.', upcast: 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for each slot level above 2nd.' },
  { name: 'Silence', level: 2, school: 'Illusion', castingTime: '1 action (ritual)', range: '120 feet', components: 'V, S', duration: 'Concentration, up to 10 minutes', classes: ['Bard', 'Cleric', 'Ranger'], description: 'For the duration, no sound can be created within or pass through a 20-foot-radius sphere centered on a point you choose within range. Any creature or object entirely inside the sphere is immune to thunder damage, and creatures are deafened while entirely inside it.' },
  { name: 'Spider Climb', level: 2, school: 'Transmutation', castingTime: '1 action', range: 'Touch', components: 'V, S, M (a drop of bitumen and a spider)', duration: 'Concentration, up to 1 hour', classes: ['Sorcerer', 'Warlock', 'Wizard'], description: 'Until the spell ends, one willing creature you touch gains the ability to move up, down, and across vertical surfaces and upside down along ceilings, while leaving its hands free. The target also gains a climbing speed equal to its walking speed.' },
  { name: 'Spiritual Weapon', level: 2, school: 'Evocation', castingTime: '1 bonus action', range: '60 feet', components: 'V, S', duration: '1 minute', classes: ['Cleric'], description: 'You create a floating, spectral weapon within range that lasts for the duration or until you cast this spell again. When you cast the spell, you can make a melee spell attack against a creature within 5 feet of the weapon. On a hit, the target takes force damage equal to 1d8 + your spellcasting ability modifier. As a bonus action on your turn, you can move the weapon up to 20 feet and repeat the attack.', upcast: 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for every two slot levels above 2nd.' },
  { name: 'Suggestion', level: 2, school: 'Enchantment', castingTime: '1 action', range: '30 feet', components: 'V, M (a snake\'s tongue and either a bit of honeycomb or a drop of sweet oil)', duration: 'Concentration, up to 8 hours', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'You suggest a course of activity (limited to a sentence or two) and magically influence a creature you can see within range that can hear and understand you. The target must make a WIS saving throw. On a failed save, it pursues the course of action you described to the best of its ability.' },
  { name: 'Web', level: 2, school: 'Conjuration', castingTime: '1 action', range: '60 feet', components: 'V, S, M (a bit of spiderweb)', duration: 'Concentration, up to 1 hour', classes: ['Sorcerer', 'Wizard'], description: 'You conjure a mass of thick, sticky webbing at a point of your choice within range. The webs fill a 20-foot cube and are difficult terrain. Each creature that starts its turn in the webs or that enters them during its turn must make a DEX saving throw. On a failed save, the creature is restrained as long as it remains in the webs or until it breaks free.' },

  // ─── LEVEL 3 ──────────────────────────────────────────────────────────
  { name: 'Animate Dead', level: 3, school: 'Necromancy', castingTime: '1 minute', range: '10 feet', components: 'V, S, M (a drop of blood, a piece of flesh, and a pinch of bone dust)', duration: 'Instantaneous', classes: ['Cleric', 'Wizard'], description: 'This spell creates an undead servant. Choose a pile of bones or a corpse within range. Your spell imbues the target with a foul mimicry of life, raising it as an undead creature. The target becomes a skeleton if you chose bones or a zombie if you chose a corpse.' },
  { name: 'Bestow Curse', level: 3, school: 'Necromancy', castingTime: '1 action', range: 'Touch', components: 'V, S', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Cleric', 'Wizard'], description: 'You touch a creature, and that creature must succeed on a WIS saving throw or become cursed for the duration of the spell. Choose the nature of the curse: disadvantage on ability checks/saving throws using a chosen ability; disadvantage on attacks against you; must use its action each turn to make a melee attack against a creature you designate; takes 1d8 additional necrotic damage from your attacks.' },
  { name: 'Clairvoyance', level: 3, school: 'Divination', castingTime: '10 minutes', range: '1 mile', components: 'V, S, M (a focus worth at least 100 gp)', duration: 'Concentration, up to 10 minutes', classes: ['Bard', 'Cleric', 'Sorcerer', 'Wizard'], description: 'You create an invisible sensor within range in a location familiar to you or in an obvious location that is unfamiliar to you. The sensor remains in place for the duration, and it can\'t be attacked or otherwise interacted with. When you cast the spell, you choose seeing or hearing. You can use the chosen sense through the sensor as if you were in its space.' },
  { name: 'Conjure Animals', level: 3, school: 'Conjuration', castingTime: '1 action', range: '60 feet', components: 'V, S', duration: 'Concentration, up to 1 hour', classes: ['Druid', 'Ranger'], description: 'You summon fey spirits that take the form of beasts and appear in unoccupied spaces that you can see within range. Choose one of the following options: one beast of CR 2 or lower, two beasts of CR 1 or lower, four beasts of CR 1/2 or lower, or eight beasts of CR 1/4 or lower.' },
  { name: 'Counterspell', level: 3, school: 'Abjuration', castingTime: '1 reaction', range: '60 feet', components: 'S', duration: 'Instantaneous', classes: ['Sorcerer', 'Warlock', 'Wizard'], description: 'You attempt to interrupt a creature in the process of casting a spell. If the creature is casting a spell of 3rd level or lower, its spell fails and has no effect. If it is casting a spell of 4th level or higher, make an ability check using your spellcasting ability. The DC equals 10 + the spell\'s level. On a success, the creature\'s spell fails and has no effect.' },
  { name: 'Daylight', level: 3, school: 'Evocation', castingTime: '1 action', range: '60 feet', components: 'V, S', duration: '1 hour', classes: ['Cleric', 'Druid', 'Paladin', 'Ranger', 'Sorcerer'], description: 'A 60-foot-radius sphere of light spreads out from a point you choose within range. The sphere is bright light and sheds dim light for an additional 60 feet. If you chose a point on an object you are holding or one that isn\'t being worn or carried, the light shines from the object with and moves with it.' },
  { name: 'Dispel Magic', level: 3, school: 'Abjuration', castingTime: '1 action', range: '120 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Bard', 'Cleric', 'Druid', 'Paladin', 'Sorcerer', 'Warlock', 'Wizard'], description: 'Choose any creature, object, or magical effect within range. Any spell of 3rd level or lower on the target ends. For each spell of 4th level or higher on the target, make an ability check using your spellcasting ability. The DC equals 10 + the spell\'s level. On a successful check, the spell ends.' },
  { name: 'Fear', level: 3, school: 'Illusion', castingTime: '1 action', range: 'Self (30-foot cone)', components: 'V, S, M (a white feather or the heart of a hen)', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'You project a phantasmal image of a creature\'s worst fears. Each creature in a 30-foot cone must succeed on a WIS saving throw or drop whatever it is holding and become frightened for the duration. While frightened by this spell, a creature must take the Dash action and move away from you by the safest available route on each of its turns.' },
  { name: 'Fireball', level: 3, school: 'Evocation', castingTime: '1 action', range: '150 feet', components: 'V, S, M (a tiny ball of bat guano and sulfur)', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'A bright streak flashes from your pointing finger to a point you choose within range and then blossoms with a low roar into an explosion of flame. Each creature in a 20-foot-radius sphere must make a DEX saving throw. A target takes 8d6 fire damage on a failed save, or half as much on a successful one.', upcast: 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.' },
  { name: 'Fly', level: 3, school: 'Transmutation', castingTime: '1 action', range: 'Touch', components: 'V, S, M (a wing feather from any bird)', duration: 'Concentration, up to 10 minutes', classes: ['Sorcerer', 'Warlock', 'Wizard'], description: 'You touch a willing creature. The target gains a flying speed of 60 feet for the duration. When the spell ends, the target falls if it is still aloft, unless it can stop the fall.', upcast: 'When you cast this spell using a spell slot of 4th level or higher, you can target one additional creature for each slot level above 3rd.' },
  { name: 'Haste', level: 3, school: 'Transmutation', castingTime: '1 action', range: '30 feet', components: 'V, S, M (a shaving of licorice root)', duration: 'Concentration, up to 1 minute', classes: ['Sorcerer', 'Wizard'], description: 'Choose a willing creature that you can see within range. Until the spell ends, the target\'s speed is doubled, it gains a +2 bonus to AC, it has advantage on DEX saving throws, and it gains an additional action on each of its turns. When the spell ends, the target can\'t move or take actions until after its next turn, as a wave of lethargy sweeps over it.' },
  { name: 'Hypnotic Pattern', level: 3, school: 'Illusion', castingTime: '1 action', range: '120 feet', components: 'S, M (a glowing stick of incense or a crystal vial filled with phosphorescent material)', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'You create a twisting pattern of colors that weaves through the air inside a 30-foot cube within range. Each creature in the area who sees the pattern must make a WIS saving throw. On a failed save, the creature becomes charmed for the duration. While charmed by this spell, the creature is incapacitated and has a speed of 0.' },
  { name: 'Lightning Bolt', level: 3, school: 'Evocation', castingTime: '1 action', range: 'Self (100-foot line)', components: 'V, S, M (a bit of fur and a rod of amber, crystal, or glass)', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'A stroke of lightning forming a line 100 feet long and 5 feet wide blasts out from you in a direction you choose. Each creature in the line must make a DEX saving throw. A creature takes 8d6 lightning damage on a failed save, or half as much on a successful one.', upcast: 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.' },
  { name: 'Mass Healing Word', level: 3, school: 'Evocation', castingTime: '1 bonus action', range: '60 feet', components: 'V', duration: 'Instantaneous', classes: ['Cleric'], description: 'As you call out words of restoration, up to six creatures of your choice that you can see within range regain hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', upcast: 'When you cast this spell using a spell slot of 4th level or higher, the healing increases by 1d4 for each slot level above 3rd.' },
  { name: 'Plant Growth', level: 3, school: 'Transmutation', castingTime: '1 action or 8 hours', range: '150 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Bard', 'Druid', 'Ranger'], description: 'This spell channels vitality into plants within a specific area. Using the spell\'s instant version, choose a point within range. All normal plants in a 100-foot radius centered on that point become thick and overgrown. A creature moving through the area must spend 4 feet of movement for every 1 foot it moves.' },
  { name: 'Revivify', level: 3, school: 'Necromancy', castingTime: '1 action', range: 'Touch', components: 'V, S, M (diamonds worth 300 gp, which the spell consumes)', duration: 'Instantaneous', classes: ['Cleric', 'Paladin'], description: 'You touch a creature that has died within the last minute. That creature returns to life with 1 hit point. This spell can\'t return to life a creature that has died of old age, nor can it restore any missing body parts.' },
  { name: 'Sending', level: 3, school: 'Evocation', castingTime: '1 action', range: 'Unlimited', components: 'V, S, M (a short piece of fine copper wire)', duration: '1 round', classes: ['Bard', 'Cleric', 'Wizard'], description: 'You send a short message of twenty-five words or less to a creature with which you are familiar. The creature hears the message in its mind, recognizes you as the sender if it knows you, and can answer in a like manner immediately. The spell enables creatures with Intelligence scores of at least 1 to understand the meaning of your message.' },
  { name: 'Slow', level: 3, school: 'Transmutation', castingTime: '1 action', range: '120 feet', components: 'V, S, M (a drop of molasses)', duration: 'Concentration, up to 1 minute', classes: ['Sorcerer', 'Wizard'], description: 'You alter time around up to six creatures of your choice in a 40-foot cube within range. Each target must succeed on a WIS saving throw or be affected by this spell for the duration. An affected target\'s speed is halved, it takes a −2 penalty to AC and DEX saving throws, and it can\'t use reactions. On its turn, it can use either an action or a bonus action, not both.' },
  { name: 'Speak with Dead', level: 3, school: 'Necromancy', castingTime: '1 action', range: '10 feet', components: 'V, S, M (burning incense)', duration: '10 minutes', classes: ['Bard', 'Cleric'], description: 'You grant the semblance of life and intelligence to a corpse of your choice within range, allowing it to answer the questions you pose. The corpse can answer up to five questions. The corpse knows only what it knew in life, including the languages it knew.' },
  { name: 'Spirit Guardians', level: 3, school: 'Conjuration', castingTime: '1 action', range: 'Self (15-foot radius)', components: 'V, S, M (a holy symbol)', duration: 'Concentration, up to 10 minutes', classes: ['Cleric'], description: 'You call forth spirits to protect you. They flit around you to a distance of 15 feet for the duration. If you are good or neutral, their spectral form appears angelic or fey (your choice). If you are evil, they appear fiendish. When you cast this spell, and as a bonus action on subsequent turns, you can designate any number of creatures you can see to be unaffected by it. Any other creature that enters the spell\'s area for the first time on a turn or starts its turn there must make a WIS saving throw.' },
  { name: 'Stinking Cloud', level: 3, school: 'Conjuration', castingTime: '1 action', range: '90 feet', components: 'V, S, M (a rotten egg or several skunk cabbage leaves)', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Sorcerer', 'Wizard'], description: 'You create a 20-foot-radius sphere of yellow, nauseating gas centered on a point within range. The cloud spreads around corners, and its area is heavily obscured. Each creature that is completely within the cloud at the start of its turn must make a CON saving throw against poison. On a failed save, the creature spends its action that turn retching and reeling.' },
  { name: 'Thunderstep', level: 3, school: 'Conjuration', castingTime: '1 action', range: 'Self', components: 'V', duration: 'Instantaneous', classes: ['Sorcerer', 'Warlock', 'Wizard'], description: 'You teleport yourself to an unoccupied space you can see within 90 feet of you. Immediately after you disappear, a thunderous boom sounds, and each creature within 10 feet of the space you left must make a CON saving throw, taking 3d10 thunder damage on a failed save, or half as much on a successful one.' },
  { name: 'Water Breathing', level: 3, school: 'Transmutation', castingTime: '1 action (ritual)', range: '30 feet', components: 'V, S, M (a short reed or piece of straw)', duration: '24 hours', classes: ['Druid', 'Ranger', 'Sorcerer', 'Wizard'], description: 'This spell grants up to ten willing creatures you can see within range the ability to breathe underwater until the spell ends. Affected creatures also retain their normal mode of respiration.' },

  // ─── LEVEL 4 ──────────────────────────────────────────────────────────
  { name: 'Banishment', level: 4, school: 'Abjuration', castingTime: '1 action', range: '60 feet', components: 'V, S, M (an item distasteful to the target)', duration: 'Concentration, up to 1 minute', classes: ['Cleric', 'Paladin', 'Sorcerer', 'Warlock', 'Wizard'], description: 'You attempt to send one creature that you can see within range to another plane of existence. The target must succeed on a CHA saving throw or be banished. If the spell ends before 1 minute has passed, the target reappears in the space it left or in the nearest unoccupied space.' },
  { name: 'Blight', level: 4, school: 'Necromancy', castingTime: '1 action', range: '30 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Druid', 'Sorcerer', 'Warlock', 'Wizard'], description: 'Necromantic energy washes over a creature of your choice that you can see within range, draining moisture and vitality from it. The target must make a CON saving throw. The target takes 8d8 necrotic damage on a failed save, or half as much on a successful one.', upcast: 'When you cast this spell using a spell slot of 5th level or higher, the damage increases by 1d8 for each slot level above 4th.' },
  { name: 'Confusion', level: 4, school: 'Enchantment', castingTime: '1 action', range: '90 feet', components: 'V, S, M (three nut shells)', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Druid', 'Sorcerer', 'Wizard'], description: 'This spell assaults and twists creatures\' minds, spawning delusions and provoking uncontrolled action. Each creature in a 10-foot-radius sphere centered on a point you choose within range must succeed on a WIS saving throw when you cast this spell or be affected by it.' },
  { name: 'Death Ward', level: 4, school: 'Abjuration', castingTime: '1 action', range: 'Touch', components: 'V, S', duration: '8 hours', classes: ['Cleric', 'Paladin'], description: 'You touch a creature and grant it a measure of protection from death. The first time the target would drop to 0 hit points as a result of taking damage, the target instead drops to 1 hit point, and the spell ends. If the spell is still in effect when the target is subjected to an effect that would kill it instantaneously, that effect is instead blocked, and the spell ends.' },
  { name: 'Dimension Door', level: 4, school: 'Conjuration', castingTime: '1 action', range: '500 feet', components: 'V', duration: 'Instantaneous', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'You teleport yourself from your current location to any other spot within range. You arrive at exactly the spot desired. It can be a place you can see, one you can visualize, or one you can describe by stating distance and direction. You can bring along objects as long as their weight doesn\'t exceed what you can carry. You can also bring one willing creature of your size or smaller who is carrying gear up to its carrying capacity.' },
  { name: 'Freedom of Movement', level: 4, school: 'Abjuration', castingTime: '1 action', range: 'Touch', components: 'V, S, M (a leather strap, bound around the arm or a similar appendage)', duration: '1 hour', classes: ['Bard', 'Cleric', 'Druid', 'Ranger'], description: 'You touch a willing creature. For the duration, the target\'s movement is unaffected by difficult terrain, and spells and other magical effects can neither reduce the target\'s speed nor cause the target to be paralyzed or restrained. The target can also spend 5 feet of movement to automatically escape from nonmagical restraints, such as manacles or a creature that has it grappled.' },
  { name: 'Greater Invisibility', level: 4, school: 'Illusion', castingTime: '1 action', range: 'Touch', components: 'V, S', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Sorcerer', 'Wizard'], description: 'You or a creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target\'s person. Unlike with the invisibility spell, the spell doesn\'t end early if the creature attacks or casts a spell.' },
  { name: 'Ice Storm', level: 4, school: 'Evocation', castingTime: '1 action', range: '300 feet', components: 'V, S, M (a pinch of dust and a few drops of water)', duration: 'Instantaneous', classes: ['Druid', 'Sorcerer', 'Wizard'], description: 'A hail of rock-hard ice pounds to the ground in a 20-foot-radius, 40-foot-high cylinder centered on a point within range. Each creature in the cylinder must make a DEX saving throw. A creature takes 2d8 bludgeoning damage and 4d6 cold damage on a failed save, or half as much on a successful one.', upcast: 'When you cast this spell using a spell slot of 5th level or higher, the bludgeoning damage increases by 1d8 for each slot level above 4th.' },
  { name: 'Polymorph', level: 4, school: 'Transmutation', castingTime: '1 action', range: '60 feet', components: 'V, S, M (a caterpillar cocoon)', duration: 'Concentration, up to 1 hour', classes: ['Bard', 'Druid', 'Sorcerer', 'Wizard'], description: 'This spell transforms a creature that you can see within range into a new form. An unwilling creature must make a WIS saving throw to avoid the effect. The spell has no effect on a shapechanger or a creature with 0 hit points. The transformation lasts for the duration, or until the target drops to 0 hit points or dies.' },
  { name: 'Wall of Fire', level: 4, school: 'Evocation', castingTime: '1 action', range: '120 feet', components: 'V, S, M (a small piece of phosphorus)', duration: 'Concentration, up to 1 minute', classes: ['Druid', 'Sorcerer', 'Wizard'], description: 'You create a wall of fire on a solid surface within range. The wall can be up to 60 feet long, 20 feet high, and 1 foot thick, or a ringed wall up to 20 feet in diameter, 20 feet high, and 1 foot thick. The wall is opaque and lasts for the duration. When the wall appears, each creature within its area must make a DEX saving throw. On a failed save, a creature takes 5d8 fire damage, or half as much on a successful save.' },

  // ─── LEVEL 5 ──────────────────────────────────────────────────────────
  { name: 'Cloudkill', level: 5, school: 'Conjuration', castingTime: '1 action', range: '120 feet', components: 'V, S', duration: 'Concentration, up to 10 minutes', classes: ['Sorcerer', 'Wizard'], description: 'You create a 20-foot-radius sphere of poisonous, yellow-green fog centered on a point you choose within range. The fog spreads around corners. Each creature that is completely within the fog at the start of its turn must make a CON saving throw. The creature takes 5d8 poison damage on a failed save, or half as much on a successful one.' },
  { name: 'Cone of Cold', level: 5, school: 'Evocation', castingTime: '1 action', range: 'Self (60-foot cone)', components: 'V, S, M (a small crystal or glass cone)', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'A blast of cold air erupts from your hands. Each creature in a 60-foot cone must make a CON saving throw. A creature takes 8d8 cold damage on a failed save, or half as much on a successful one. A creature killed by this spell becomes a frozen statue until it thaws.', upcast: 'When you cast this spell using a spell slot of 6th level or higher, the damage increases by 1d8 for each slot level above 5th.' },
  { name: 'Dominate Person', level: 5, school: 'Enchantment', castingTime: '1 action', range: '60 feet', components: 'V, S', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Sorcerer', 'Wizard'], description: 'You attempt to beguile a humanoid that you can see within range. It must succeed on a WIS saving throw or be charmed by you for the duration. While the target is charmed, you have a telepathic link with it as long as you are on the same plane. You can use this telepathic link to issue commands to the creature while you are conscious (no action required).' },
  { name: 'Flame Strike', level: 5, school: 'Evocation', castingTime: '1 action', range: '60 feet', components: 'V, S, M (pinch of sulfur)', duration: 'Instantaneous', classes: ['Cleric'], description: 'A vertical column of divine fire roars down from the heavens in a location you specify. Each creature in a 10-foot-radius, 40-foot-high cylinder centered on a point within range must make a DEX saving throw. A creature takes 4d6 fire damage and 4d6 radiant damage on a failed save, or half as much on a successful one.', upcast: 'When you cast this spell using a spell slot of 6th level or higher, the fire damage or the radiant damage (your choice) increases by 1d6 for each slot level above 5th.' },
  { name: 'Hold Monster', level: 5, school: 'Enchantment', castingTime: '1 action', range: '90 feet', components: 'V, S, M (a small, straight piece of iron)', duration: 'Concentration, up to 1 minute', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'Choose a creature that you can see within range. The target must succeed on a WIS saving throw or be paralyzed for the duration. This spell has no effect on undead. At the end of each of its turns, the target can make another WIS saving throw. On a success, the spell ends on the target.', upcast: 'When you cast this spell using a spell slot of 6th level or higher, you can target one additional creature for each slot level above 5th.' },
  { name: 'Insect Plague', level: 5, school: 'Conjuration', castingTime: '1 action', range: '300 feet', components: 'V, S, M (a few grains of sugar, some kernels of grain, and a smear of fat)', duration: 'Concentration, up to 10 minutes', classes: ['Cleric', 'Druid', 'Sorcerer'], description: 'Swarming, biting locusts fill a 20-foot-radius sphere centered on a point you choose within range. The sphere spreads around corners. The sphere remains for the duration, and its area is lightly obscured. The sphere\'s area is difficult terrain. When the area appears, each creature in it must make a CON saving throw. A creature takes 4d10 piercing damage on a failed save, or half as much on a successful one.' },
  { name: 'Mass Cure Wounds', level: 5, school: 'Evocation', castingTime: '1 action', range: '60 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Bard', 'Cleric', 'Druid'], description: 'A wave of healing energy washes out from a point of your choice within range. Choose up to six creatures in a 30-foot-radius sphere centered on that point. Each target regains hit points equal to 3d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', upcast: 'When you cast this spell using a spell slot of 6th level or higher, the healing increases by 1d8 for each slot level above 5th.' },
  { name: 'Raise Dead', level: 5, school: 'Necromancy', castingTime: '1 hour', range: 'Touch', components: 'V, S, M (a diamond worth at least 500 gp, which the spell consumes)', duration: 'Instantaneous', classes: ['Bard', 'Cleric', 'Paladin'], description: 'You return a dead creature you touch to life, provided that it has been dead no longer than 10 days. If the creature\'s soul is both willing and at liberty to rejoin the body, the creature returns to life with 1 hit point. The creature also suffers a −4 penalty to all attack rolls, saving throws, and ability checks. Every time the creature finishes a long rest, the penalty is reduced by 1 until it disappears.' },
  { name: 'Scrying', level: 5, school: 'Divination', castingTime: '10 minutes', range: 'Self', components: 'V, S, M (a focus worth at least 1,000 gp)', duration: 'Concentration, up to 10 minutes', classes: ['Bard', 'Cleric', 'Druid', 'Warlock', 'Wizard'], description: 'You can see and hear a particular creature you choose that is on the same plane of existence as you. The target must make a WIS saving throw, which is modified by how well you know the target and the sort of physical connection you have to it. On a failed save, the spell creates an invisible sensor within 10 feet of the target.' },
  { name: 'Teleportation Circle', level: 5, school: 'Conjuration', castingTime: '1 minute', range: '10 feet', components: 'V, M (rare chalks and inks infused with precious gems worth 50 gp)', duration: '1 round', classes: ['Bard', 'Sorcerer', 'Wizard'], description: 'As you cast the spell, you draw a 10-foot-diameter circle on the ground inscribed with sigils that link your location to a permanent teleportation circle of your choice whose sigil sequence you know and that is on the same plane of existence as you. A shimmering portal opens within the circle you drew and remains open until the end of your next turn.' },
  { name: 'Wall of Force', level: 5, school: 'Evocation', castingTime: '1 action', range: '120 feet', components: 'V, S, M (a pinch of powder made by crushing a clear gemstone)', duration: 'Concentration, up to 10 minutes', classes: ['Wizard'], description: 'An invisible wall of force springs into existence at a point you choose within range. The wall appears in any orientation you choose, as a horizontal or vertical barrier or at an angle. It can be free floating or resting on a solid surface. You can form it into a hemispherical dome or a sphere with a radius of up to 10 feet, or you can shape a flat surface made up of ten 10-foot-by-10-foot panels.' },

  // ─── LEVEL 6 ──────────────────────────────────────────────────────────
  { name: 'Chain Lightning', level: 6, school: 'Evocation', castingTime: '1 action', range: '150 feet', components: 'V, S, M (a bit of fur; a piece of amber, glass, or a crystal rod; and three silver pins)', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'You create a bolt of lightning that arcs toward a target of your choice that you can see within range. Three bolts then leap from that target to as many as three other targets, each of which must be within 30 feet of the first target. A target can be a creature or an object and can be targeted by only one of the bolts. A target must make a DEX saving throw. The target takes 10d8 lightning damage on a failed save, or half as much on a successful one.', upcast: 'When you cast this spell using a spell slot of 7th level or higher, one additional bolt leaps from the first target to another target for each slot level above 6th.' },
  { name: 'Disintegrate', level: 6, school: 'Transmutation', castingTime: '1 action', range: '60 feet', components: 'V, S, M (a lodestone and a pinch of dust)', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'A thin green ray springs from your pointing finger to a target you choose within range. The target can be a creature, an object, or a creation of magical force, such as the wall created by wall of force. A creature targeted by this spell must make a DEX saving throw. On a failed save, the target takes 10d6 + 40 force damage. The target is disintegrated if this damage leaves it with 0 hit points.', upcast: 'When you cast this spell using a spell slot of 7th level or higher, the damage increases by 3d6 for each slot level above 6th.' },
  { name: 'Globe of Invulnerability', level: 6, school: 'Abjuration', castingTime: '1 action', range: 'Self (10-foot radius)', components: 'V, S, M (a glass or crystal bead that shatters when the spell ends)', duration: 'Concentration, up to 1 minute', classes: ['Sorcerer', 'Wizard'], description: 'An immobile, faintly shimmering barrier springs into existence in a 10-foot radius around you and remains for the duration. Any spell of 5th level or lower cast from outside the barrier can\'t affect creatures or objects within it, even if the spell is cast using a higher level spell slot.' },
  { name: 'Harm', level: 6, school: 'Necromancy', castingTime: '1 action', range: '60 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Cleric'], description: 'You unleash a virulent disease on a creature that you can see within range. The target must make a CON saving throw. On a failed save, it takes 14d6 necrotic damage, or half as much on a successful save. The damage can\'t reduce the target\'s hit points below 1. If the target fails the saving throw, its hit point maximum is reduced for 1 hour by an amount equal to the necrotic damage it took.' },
  { name: 'Heal', level: 6, school: 'Evocation', castingTime: '1 action', range: '60 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Cleric', 'Druid'], description: 'Choose a creature that you can see within range. A surge of positive energy washes through the creature, causing it to regain 70 hit points. This spell also ends blindness, deafness, and any diseases affecting the target. This spell has no effect on constructs or undead.', upcast: 'When you cast this spell using a spell slot of 7th level or higher, the amount of healing increases by 10 for each slot level above 6th.' },
  { name: 'True Seeing', level: 6, school: 'Divination', castingTime: '1 action', range: 'Touch', components: 'V, S, M (an ointment worth 25 gp made from mushroom powder, saffron, and fat)', duration: '1 hour', classes: ['Bard', 'Cleric', 'Sorcerer', 'Warlock', 'Wizard'], description: 'You give the willing creature you touch the ability to see things as they actually are. For the duration, the creature has truesight, notices secret doors hidden by magic, and can see into the Ethereal Plane, all out to a range of 120 feet.' },

  // ─── LEVEL 7 ──────────────────────────────────────────────────────────
  { name: 'Fire Storm', level: 7, school: 'Evocation', castingTime: '1 action', range: '150 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Cleric', 'Druid', 'Sorcerer'], description: 'A storm made up of sheets of roaring flame appears in a location you choose within range. The area of the storm consists of up to ten 10-foot cubes, which you can arrange as you wish. Each cube must have at least one face adjacent to the face of another cube. Each creature in the area must make a DEX saving throw. It takes 7d10 fire damage on a failed save, or half as much on a successful one.' },
  { name: 'Plane Shift', level: 7, school: 'Conjuration', castingTime: '1 action', range: 'Touch', components: 'V, S, M (a forked, metal rod worth at least 250 gp, attuned to a specific plane)', duration: 'Instantaneous', classes: ['Cleric', 'Druid', 'Sorcerer', 'Warlock', 'Wizard'], description: 'You and up to eight willing creatures who link hands in a circle are transported to a different plane of existence. You can specify a target destination in general terms, such as the City of Brass on the Elemental Plane of Fire or the palace of Dispater on the second level of the Nine Hells, and you appear in or near that destination.' },
  { name: 'Prismatic Spray', level: 7, school: 'Evocation', castingTime: '1 action', range: 'Self (60-foot cone)', components: 'V, S', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'Eight multicolored rays of light flash from your hand. Each ray hits one creature that you can see within range. Roll 1d8 for each ray (rerolling 8s) to determine its color and effect: Red (10d6 fire), Orange (10d6 acid), Yellow (10d6 lightning), Green (10d6 poison), Blue (10d6 cold), Indigo (restrained then paralyzed then petrified), Violet (blinded then transported), Special (struck by two rays).' },
  { name: 'Resurrection', level: 7, school: 'Necromancy', castingTime: '1 hour', range: 'Touch', components: 'V, S, M (a diamond worth at least 1,000 gp, which the spell consumes)', duration: 'Instantaneous', classes: ['Bard', 'Cleric'], description: 'You touch a dead creature that has been dead for no more than a century, that didn\'t die of old age, and that isn\'t undead. If its soul is free and willing, the target returns to life with all its hit points. This spell neutralizes any poisons and cures normal diseases afflicting the creature when it died.' },
  { name: 'Reverse Gravity', level: 7, school: 'Transmutation', castingTime: '1 action', range: '100 feet', components: 'V, S, M (a lodestone and iron filings)', duration: 'Concentration, up to 1 minute', classes: ['Druid', 'Sorcerer', 'Wizard'], description: 'This spell reverses gravity in a 50-foot-radius, 100-foot-high cylinder centered on a point within range. All creatures and objects that aren\'t somehow anchored to the ground in the area fall upward and reach the top of the area. A creature can make a DEX saving throw to grab onto a fixed object it can reach, thus avoiding the fall.' },

  // ─── LEVEL 8 ──────────────────────────────────────────────────────────
  { name: 'Antimagic Field', level: 8, school: 'Abjuration', castingTime: '1 action', range: 'Self (10-foot radius)', components: 'V, S, M (a pinch of powdered iron or iron filings)', duration: 'Concentration, up to 1 hour', classes: ['Cleric', 'Wizard'], description: 'A 10-foot-radius invisible sphere of antimagic surrounds you. This area is divorced from the magical energy that suffuses the multiverse. Within the sphere, spells can\'t be cast, summoned creatures disappear, and even magic items become mundane.' },
  { name: 'Dominate Monster', level: 8, school: 'Enchantment', castingTime: '1 action', range: '60 feet', components: 'V, S', duration: 'Concentration, up to 1 hour', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'You attempt to beguile a creature that you can see within range. It must succeed on a WIS saving throw or be charmed by you for the duration. While the creature is charmed, you have a telepathic link with it as long as you are on the same plane of existence.' },
  { name: 'Earthquake', level: 8, school: 'Evocation', castingTime: '1 action', range: '500 feet', components: 'V, S, M (a pinch of dirt, a piece of rock, and a lump of clay)', duration: 'Concentration, up to 1 minute', classes: ['Cleric', 'Druid', 'Sorcerer'], description: 'You create a seismic disturbance at a point on the ground you can see within range. For the duration, an intense tremor rips through the ground in a 100-foot-radius circle centered on that point. Each creature on the ground in that area must make a CON saving throw. On a failed save, the creature is knocked prone.' },
  { name: 'Power Word Stun', level: 8, school: 'Enchantment', castingTime: '1 action', range: '60 feet', components: 'V', duration: 'Instantaneous', classes: ['Sorcerer', 'Warlock', 'Wizard'], description: 'You speak a word of power that overwhelms the mind of one creature you can see within range, leaving it dumbfounded. If the target has 150 hit points or fewer, it is stunned. Otherwise, the spell has no effect. The stunned target must make a CON saving throw at the end of each of its turns. On a successful save, the stunning effect ends.' },

  // ─── LEVEL 9 ──────────────────────────────────────────────────────────
  { name: 'Foresight', level: 9, school: 'Divination', castingTime: '1 minute', range: 'Touch', components: 'V, S, M (a hummingbird feather)', duration: '8 hours', classes: ['Bard', 'Druid', 'Warlock', 'Wizard'], description: 'You touch a willing creature and bestow a limited ability to see into the immediate future. For the duration, the target can\'t be surprised and has advantage on attack rolls, ability checks, and saving throws. Additionally, other creatures have disadvantage on attack rolls against the target for the duration.' },
  { name: 'Mass Heal', level: 9, school: 'Evocation', castingTime: '1 action', range: '60 feet', components: 'V, S', duration: 'Instantaneous', classes: ['Cleric'], description: 'A flood of healing energy flows from you into injured creatures around you. You restore up to 700 hit points, divided as you choose among any number of creatures that you can see within range. Creatures healed by this spell are also cured of all diseases and any effect making them blinded or deafened. This spell has no effect on undead or constructs.' },
  { name: 'Meteor Swarm', level: 9, school: 'Evocation', castingTime: '1 action', range: '1 mile', components: 'V, S', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'Blazing orbs of fire plummet to the ground at four different points you can see within range. Each creature in a 40-foot-radius sphere centered on each point you choose must make a DEX saving throw. The sphere spreads around corners. A creature takes 20d6 fire damage and 20d6 bludgeoning damage on a failed save, or half as much on a successful one. A creature in the area of more than one fiery burst is affected only once.' },
  { name: 'Power Word Kill', level: 9, school: 'Enchantment', castingTime: '1 action', range: '60 feet', components: 'V', duration: 'Instantaneous', classes: ['Bard', 'Sorcerer', 'Warlock', 'Wizard'], description: 'You utter a word of power that can compel one creature you can see within range to die instantly. If the creature you choose has 100 hit points or fewer, it dies. Otherwise, the spell has no effect.' },
  { name: 'Time Stop', level: 9, school: 'Transmutation', castingTime: '1 action', range: 'Self', components: 'V', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'You briefly stop the flow of time for everyone but yourself. No time passes for other creatures, while you take 1d4 + 1 turns in a row, during which you can use actions and move as normal. This effect ends if one of the actions you use during this period, or any effects that you create during this period, affects a creature other than you or an object being worn or carried by someone other than you.' },
  { name: 'True Resurrection', level: 9, school: 'Necromancy', castingTime: '1 hour', range: 'Touch', components: 'V, S, M (a sprinkle of holy water and diamonds worth at least 25,000 gp, which the spell consumes)', duration: 'Instantaneous', classes: ['Cleric', 'Druid'], description: 'You touch a creature that has been dead for no longer than 200 years and that died for any reason except old age. If the creature\'s soul is free and willing, the creature is restored to life with all its hit points. This spell closes all wounds, neutralizes any poison, cures all diseases, and lifts any curses afflicting the creature when it died.' },
  { name: 'Wish', level: 9, school: 'Conjuration', castingTime: '1 action', range: 'Self', components: 'V', duration: 'Instantaneous', classes: ['Sorcerer', 'Wizard'], description: 'Wish is the mightiest spell a mortal creature can cast. By simply speaking aloud, you can alter the very foundations of reality in accord with your desires. The basic use of this spell is to duplicate any other spell of 8th level or lower. You don\'t need to meet any requirements in that spell, including costly components. The spell simply takes effect. Alternatively, you can create one of the following effects of your choice, or request something different (which may have severe consequences).' },
];

export function getSpellsForClass(className: string): SpellData[] {
  return SPELL_LIST.filter(s => s.classes.includes(className));
}

export function getSpellsForClassByLevel(className: string, maxLevel: number): Map<number, SpellData[]> {
  const map = new Map<number, SpellData[]>();
  for (let i = 0; i <= 9; i++) map.set(i, []);
  getSpellsForClass(className).forEach(spell => {
    if (spell.level <= maxLevel) {
      map.get(spell.level)!.push(spell);
    }
  });
  return map;
}
